    DROP TABLE IF EXISTS datascience.ae_zoominfo_standard_us;

    CREATE TABLE
        datascience.ae_zoominfo_standard_us DISTSTYLE EVEN
                                            INTERLEAVED SORTKEY
                                                (
                                                zi_c_location_id,
                                                zi_c_company_id,
                                                zi_es_location_id
                                                ) AS
    SELECT
        zi_c_location_id,
        zi_c_company_id,
        zi_es_location_id,
        zi_c_name,
        zi_c_name_display,
        zi_c_names_other,
        zi_c_url,
        zi_c_street,
        zi_c_street_2,
        zi_c_city,
        zi_c_state,
        zi_c_zip,
        zi_c_country,
        zi_c_county,
        zi_c_latitude,
        zi_c_longitude,
        zi_c_year_founded,
        zi_c_phone,
        zi_c_fax,
        zi_c_ein,

        UPPER(REGEXP_REPLACE(zi_c_name, '[^a-zA-Z0-9 ]', ''))             AS zi_eng_companyname,
        UPPER(REGEXP_REPLACE(zi_c_name_display, '[^a-zA-Z0-9 ]', ''))     AS zi_eng_dba,
        UPPER(REGEXP_REPLACE(zi_c_names_other, '[^a-zA-Z0-9 ]', ''))      AS zi_eng_dba2,
        REPLACE(REPLACE(REPLACE(
                                UPPER(TRIM(zi_c_url))
                            , 'WWW.', '')
                    , 'HTTPS://', '')
            , 'HTTP://', '')
