                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                REGEXP_REPLACE(
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        CONCAT(CONCAT(zi_c_street, ' '), zi_c_street_2),
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        '[^a-zA-Z0-9 ]',
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        ''),
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                '([0-9]+)[A-Z]{2}',
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                '$1')),
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        ' AVE ',
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        ' AVENUE '),
