                                                                                                ' VLY ', ' VALLEY '),
                                                                                        ' VW ', ' VIEW '), ' XING ',
                                                                                ' CROSSING '), ' S ', ' SOUTH '), ' N ',
                                                                ' NORTH '), ' W ', ' WEST '), ' E ', ' EAST '), ' SE ',
                                        ' SOUTHEAST '), ' NE ', ' NORTHEAST '), ' SW ', ' SOUTHWEST '), ' NW ',
                ' NORTHWEST ')                                            AS zi_eng_address,
        REGEXP_SUBSTR(zi_c_street, '^[0-9]+')                             AS zi_eng_street_num,
        state_code                                                        AS zi_eng_state,
        UPPER(zi_c_city)                                                  AS zi_eng_city,
        LPAD(SPLIT_PART(TRIM(zi_c_zip), '-', 1), 5, '0')                  AS zi_eng_zipcode,
        SUBSTRING(LPAD(SPLIT_PART(TRIM(zi_c_zip), '-', 1), 5, '0'), 1, 3) AS zi_eng_zipcode_threedigits,
        LPAD(SPLIT_PART(TRIM(zi_c_zip), '-', 2), 4, '0')                  AS zi_eng_zip4,
        UPPER(zi_c_county)                                                AS zi_eng_county,
        UPPER(zi_c_country)                                               AS zi_eng_country,
        LTRIM(REGEXP_SUBSTR(zi_c_phone, ' [0-9]+'))                       AS zi_eng_phone_number,
        REGEXP_SUBSTR(zi_c_phone, '\\+[0-9]+')                            AS zi_eng_phone_countrycode,
        LTRIM(REGEXP_SUBSTR(zi_c_fax, ' [0-9]+'))                         AS zi_eng_fax_number,
        REGEXP_SUBSTR(zi_c_fax, '\\+[0-9]+')                              AS zi_eng_fax_countrycode


    FROM zoominfo.comp_standard_global
        LEFT JOIN state_lookup
                ON UPPER(comp_standard_global.zi_c_state) = state_lookup.state_name_upper

    WHERE zi_c_country = 'United States';

